    var a = 1;    // function-scoped
    let b = 2;    // block-scoped
    const c = 3;  // block-scoped
  }
  console.log(a); // Works: 1
  // console.log(b); // Error: b is not defined
  // console.log(c); // Error: c is not defined
}

// Prefer let/const for predictable scope!

if (true) {
  let x = 10;
  console.log(x); // 10
}
// console.log(x); // Error: x is not defined here

function createCounter() {
  let count = 0; // 'count' is in the closure

  return function() {
    count++;
    return count;
  };
}

const counter = createCounter();
console.log(counter()); // 1
console.log(counter()); // 2
// 'count' is private and preserved between calls!

function makeGreeter(name) {
  return function() {
    return 'Hello, ' + name;
  };
}
const greetAlex = makeGreeter('Alex');
console.log(greetAlex()); // 'Hello, Alex'

const person = {
  name: 'Taylor',
  greet: function() {
    console.log('Hi, I\'m ' + this.name);
  }
};

person.greet(); // 'Hi, I\'m Taylor' - 'this' is person

// Arrow functions handle 'this' differently!
const arrowGreet = () => {
  console.log(this.name); // 'this' is NOT person here
};

const user = {
