function divide(a, b) {
  try {
    if (b === 0) throw new Error('Cannot divide by zero');
    return a / b;
  } catch (error) {
    console.error('Error:', error.message);
    return null;
  } finally {
    console.log('Division attempt finished');
  }
}

divide(10, 2); // 5
divide(10, 0); // Error + null

